class AgentError(Exception):
    """Base for all agent-layer errors."""

class RecoverableToolError(AgentError):
    """The tool failed but the agent run can continue."""
    def __init__(self, message: str, tool_name: str):
        super().__init__(message)
        self.tool_name = tool_name

class FatalAgentError(AgentError):
    """Unrecoverable; the whole run should abort."""

class ToolTimeoutError(RecoverableToolError):
    pass

class UnknownToolError(RecoverableToolError):
    pass

import logging
import time

log = logging.getLogger(__name__)

def safe_dispatch(call: dict) -> dict:
    """Run one tool call; always return a result dict (never raise)."""
    tool_name = call.get("name", "<unknown>")
    try:
        result = dispatch(call)           # may raise any exception
    except UnknownToolError as exc:
        log.warning("Unknown tool requested: %s", exc.tool_name)
        return {"type": "tool_error", "content": f"Unknown tool: {tool_name}"}
    except ToolTimeoutError:
        log.warning("Tool %s timed out", tool_name)
        return {"type": "tool_error", "content": "Tool timed out; try a simpler request."}
    except RecoverableToolError as exc:
        log.exception("Recoverable tool error in %s", tool_name)
        return {"type": "tool_error", "content": str(exc)}
    except FatalAgentError:
        raise   # let it propagate; the agent loop catches it at the top level
    except Exception:
        log.exception("Unexpected error in tool %s", tool_name)
        return {"type": "tool_error", "content": "Internal error. Please try again."}
    else:
        log.debug("Tool %s succeeded", tool_name)
        return {"type": "tool_result", "content": result}

import threading

_semaphore = threading.Semaphore(4)   # max 4 concurrent tool calls

def bounded_dispatch(call: dict) -> dict:
    _semaphore.acquire()
    try:
        return safe_dispatch(call)
    finally:
        _semaphore.release()          # always released, even if safe_dispatch raises

import time
import random

class RateLimitError(Exception):
    pass

class TransientError(Exception):
    pass

def call_llm_with_retry(client, messages, max_retries=4):
    """Retry on rate-limit and transient errors with jittered back-off."""
    delay = 1.0
    for attempt in range(max_retries + 1):
        try:
            return client.chat.completions.create(
                model="claude-opus-4-5",
                messages=messages,
            )
        except RateLimitError:
            if attempt == max_retries:
                raise
            sleep_time = delay + random.uniform(0, delay * 0.3)
            print(f"Rate limited. Sleeping {sleep_time:.1f}s (attempt {attempt + 1})")
            time.sleep(sleep_time)
            delay = min(delay * 2, 60)   # cap at 60 s
        except TransientError as exc:
            if attempt == max_retries:
                raise
            time.sleep(delay)
            delay *= 2
        # Any other exception propagates immediately — not retried

