import json
import os
import tempfile

def save_checkpoint(state: dict, path: str) -> None:
    """Write state atomically; on failure, the original file is untouched."""
    dir_name = os.path.dirname(path) or "."
    tmp_fd, tmp_path = tempfile.mkstemp(dir=dir_name, suffix=".tmp")
    try:
        try:
            with os.fdopen(tmp_fd, "w") as fh:
                json.dump(state, fh, indent=2)
            os.replace(tmp_path, path)  # atomic on POSIX
        except Exception:
            log.exception("Checkpoint write failed; original file is safe.")
            raise
    finally:
        # Clean up the temp file if os.replace did not consume it
        if os.path.exists(tmp_path):
            try:
                os.unlink(tmp_path)
            except OSError:
                pass  # best-effort cleanup in finally is acceptable

def load_checkpoint(path: str) -> dict:
    """Load state; return empty dict if file is missing or corrupt."""
    try:
        with open(path) as fh:
            return json.load(fh)
    except FileNotFoundError:
        return {}
    except json.JSONDecodeError as exc:
        log.error("Corrupt checkpoint at %s: %s", path, exc)
        return {}

